#include<bits/stdc++.h>
using namespace std;
double b[100010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        double sum,pf;
        long long lson,rson;
        double tag;
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum=(a[a[x].lson].sum+a[a[x].rson].sum);
        a[x].pf=(a[a[x].lson].pf+a[a[x].rson].pf);
    }
    void pushadd(long long x,double v)
    {
        a[x].pf+=(v*v)*(a[x].r-a[x].l+1)+2.0*v*a[x].sum;
        a[x].sum=(a[x].sum+((a[x].r-a[x].l+1)*v));
        a[x].tag+=v;
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        double tg=a[x].tag;
        pushadd(ls,tg);
        pushadd(rs,tg);
        a[x].tag=0.0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        a[x].tag=0.0;
        if(l==r)
        {
            a[x].sum=b[l];
            a[x].pf=b[l]*b[l];
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,double z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushadd(x,z);
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    double getsum(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0.0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        pushdown(x);
        return (getsum(a[x].lson,l,r)+getsum(a[x].rson,l,r));
    }
    double getpf(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0.0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].pf;
        }
        pushdown(x);
        return (getpf(a[x].lson,l,r)+getpf(a[x].rson,l,r));
    }
}t;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%lf",&b[i]);
    }
    t.init(1,n);
    while(m--)
    {
        int op;
        int x,y;
        double k;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
        {
            scanf("%lf",&k);
            t.add(1,x,y,k);
        }
        else if(op==2)
        {
            printf("%.4lf\n",t.getsum(1,x,y)/(y-x+1));
        }
        else
        {
            double ave=t.getsum(1,x,y)/(y-x+1);
            double s2=t.getpf(1,x,y)/(y-x+1)-ave*ave;
            printf("%.4lf\n",s2);
        }
    }
    return 0;
}
